import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import Dataset, DataLoader
import torchvision.models as models
import torchvision.transforms as transforms
from torchvision.datasets import ImageFolder
import requests
import os
from pathlib import Path
from typing import Optional, Dict, Any
import hashlib
from tqdm import tqdm


class ModelDownloader:
    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
    
    def download_file(self, url: str, filename: Optional[str] = None) -> Path:
        if filename is None:
            filename = hashlib.md5(url.encode()).hexdigest() + ".pth"
        
        filepath = self.cache_dir / filename
        
        if filepath.exists():
            print(f"Model already cached at {filepath}")
            return filepath
        
        print(f"Downloading model from {url}")
        response = requests.get(url, stream=True)
        response.raise_for_status()
        
        total_size = int(response.headers.get('content-length', 0))
        
        with open(filepath, 'wb') as f:
            with tqdm(total=total_size, unit='B', unit_scale=True) as pbar:
                for chunk in response.iter_content(chunk_size=8192):
                    if chunk:
                        f.write(chunk)
                        pbar.update(len(chunk))
        
        print(f"Model downloaded to {filepath}")
        return filepath
    
    def load_checkpoint(self, url: str, filename: Optional[str] = None, map_location: str = 'cpu') -> Dict[str, Any]:
        filepath = self.download_file(url, filename)
        checkpoint = torch.load(filepath, map_location=map_location)
        return checkpoint


class PretrainedModelLoader:
    def __init__(self, cache_dir: str = "./model_cache"):
        self.downloader = ModelDownloader(cache_dir)
        self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    
    def load_from_url(self, url: str, model_architecture: nn.Module, filename: Optional[str] = None) -> nn.Module:
        checkpoint = self.downloader.load_checkpoint(url, filename, map_location=self.device)
        
        if isinstance(checkpoint, dict):
            if 'model_state_dict' in checkpoint:
                model_architecture.load_state_dict(checkpoint['model_state_dict'])
            elif 'state_dict' in checkpoint:
                model_architecture.load_state_dict(checkpoint['state_dict'])
            else:
                model_architecture.load_state_dict(checkpoint)
        else:
            model_architecture.load_state_dict(checkpoint)
        
        return model_architecture
    
    def load_torchvision_model(self, model_name: str, pretrained: bool = True, num_classes: Optional[int] = None) -> nn.Module:
        model_func = getattr(models, model_name)
        model = model_func(pretrained=pretrained)
        
        if num_classes is not None:
            if hasattr(model, 'fc'):
                in_features = model.fc.in_features
                model.fc = nn.Linear(in_features, num_classes)
            elif hasattr(model, 'classifier'):
                if isinstance(model.classifier, nn.Sequential):
                    in_features = model.classifier[-1].in_features
                    model.classifier[-1] = nn.Linear(in_features, num_classes)
                else:
                    in_features = model.classifier.in_features
                    model.classifier = nn.Linear(in_features, num_classes)
        
        return model


class CustomDataset(Dataset):
    def __init__(self, data, labels, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        
        if self.transform:
            sample = self.transform(sample)
        
        return sample, label


class TransferLearningTrainer:
    def __init__(self, model: nn.Module, device: Optional[torch.device] = None):
        self.model = model
        self.device = device if device else torch.device("cuda" if torch.cuda.is_available() else "cpu")
        self.model.to(self.device)
    
    def freeze_layers(self, freeze_until: Optional[str] = None):
        if freeze_until is None:
            for param in self.model.parameters():
                param.requires_grad = False
        else:
            freeze = True
            for name, param in self.model.named_parameters():
                if freeze_until in name:
                    freeze = False
                param.requires_grad = not freeze
    
    def unfreeze_all(self):
        for param in self.model.parameters():
            param.requires_grad = True
    
    def train_epoch(self, dataloader: DataLoader, criterion: nn.Module, optimizer: optim.Optimizer) -> float:
        self.model.train()
        running_loss = 0.0
        correct = 0
        total = 0
        
        for inputs, labels in tqdm(dataloader, desc="Training"):
            inputs, labels = inputs.to(self.device), labels.to(self.device)
            
            optimizer.zero_grad()
            outputs = self.model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            
            running_loss += loss.item()
            _, predicted = outputs.max(1)
            total += labels.size(0)
            correct += predicted.eq(labels).sum().item()
        
        epoch_loss = running_loss / len(dataloader)
        accuracy = 100. * correct / total
        return epoch_loss, accuracy
    
    def validate(self, dataloader: DataLoader, criterion: nn.Module) -> tuple:
        self.model.eval()
        running_loss = 0.0
        correct = 0
        total = 0
        
        with torch.no_grad():
            for inputs, labels in tqdm(dataloader, desc="Validation"):
                inputs, labels = inputs.to(self.device), labels.to(self.device)
                outputs = self.model(inputs)
                loss = criterion(outputs, labels)
                
                running_loss += loss.item()
                _, predicted = outputs.max(1)
                total += labels.size(0)
                correct += predicted.eq(labels).sum().item()
        
        val_loss = running_loss / len(dataloader)
        accuracy = 100. * correct / total
        return val_loss, accuracy
    
    def fine_tune(self, train_loader: DataLoader, val_loader: DataLoader, 
                  num_epochs: int = 10, lr: float = 0.001, 
                  freeze_backbone: bool = True, unfreeze_epoch: Optional[int] = None):
        
        if freeze_backbone:
            self.freeze_layers()
        
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()), lr=lr)
        scheduler = optim.lr_scheduler.ReduceLROnPlateau(optimizer, mode='min', patience=2, verbose=True)
        
        best_val_loss = float('inf')
        
        for epoch in range(num_epochs):
            print(f"\nEpoch {epoch+1}/{num_epochs}")
            
            if unfreeze_epoch and epoch == unfreeze_epoch:
                print("Unfreezing all layers")
                self.unfreeze_all()
                optimizer = optim.Adam(self.model.parameters(), lr=lr/10)
            
            train_loss, train_acc = self.train_epoch(train_loader, criterion, optimizer)
            val_loss, val_acc = self.validate(val_loader, criterion)
            
            print(f"Train Loss: {train_loss:.4f}, Train Acc: {train_acc:.2f}%")
            print(f"Val Loss: {val_loss:.4f}, Val Acc: {val_acc:.2f}%")
            
            scheduler.step(val_loss)
            
            if val_loss < best_val_loss:
                best_val_loss = val_loss
                self.save_checkpoint('best_model.pth', epoch, optimizer, val_loss)
        
        return self.model
    
    def save_checkpoint(self, filepath: str, epoch: int, optimizer: optim.Optimizer, loss: float):
        checkpoint = {
            'epoch': epoch,
            'model_state_dict': self.model.state_dict(),
            'optimizer_state_dict': optimizer.state_dict(),
            'loss': loss,
        }
        torch.save(checkpoint, filepath)
        print(f"Checkpoint saved to {filepath}")


class TransferLearningPipeline:
    def __init__(self, cache_dir: str = "./model_cache"):
        self.loader = PretrainedModelLoader(cache_dir)
        self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    
    def create_model_from_url(self, url: str, architecture: str, num_classes: int) -> nn.Module:
        base_model = self.loader.load_torchvision_model(architecture, pretrained=False)
        model = self.loader.load_from_url(url, base_model)
        
        if hasattr(model, 'fc'):
            in_features = model.fc.in_features
            model.fc = nn.Linear(in_features, num_classes)
        elif hasattr(model, 'classifier'):
            if isinstance(model.classifier, nn.Sequential):
                in_features = model.classifier[-1].in_features
                model.classifier[-1] = nn.Linear(in_features, num_classes)
            else:
                in_features = model.classifier.in_features
                model.classifier = nn.Linear(in_features, num_classes)
        
        return model
    
    def create_model_pretrained(self, architecture: str, num_classes: int) -> nn.Module:
        return self.loader.load_torchvision_model(architecture, pretrained=True, num_classes=num_classes)
    
    def prepare_data_loaders(self, train_dir: str, val_dir: str, batch_size: int = 32, 
                            img_size: int = 224) -> tuple:
        transform_train = transforms.Compose([
            transforms.Resize((img_size, img_size)),
            transforms.RandomHorizontalFlip(),
            transforms.RandomRotation(10),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
        
        transform_val = transforms.Compose([
            transforms.Resize((img_size, img_size)),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
        
        train_dataset = ImageFolder(train_dir, transform=transform_train)
        val_dataset = ImageFolder(val_dir, transform=transform_val)
        
        train_loader = DataLoader(train_dataset, batch_size=batch_size, shuffle=True, num_workers=4)
        val_loader = DataLoader(val_dataset, batch_size=batch_size, shuffle=False, num_workers=4)
        
        return train_loader, val_loader
    
    def run_pipeline(self, model_source: str, architecture: str, num_classes: int,
                    train_dir: str, val_dir: str, num_epochs: int = 10, 
                    batch_size: int = 32, lr: float = 0.001, 
                    freeze_backbone: bool = True, unfreeze_epoch: Optional[int] = None):
        
        if model_source.startswith('http'):
            model = self.create_model_from_url(model_source, architecture, num_classes)
        else:
            model = self.create_model_pretrained(architecture, num_classes)
        
        train_loader, val_loader = self.prepare_data_loaders(train_dir, val_dir, batch_size)
        
        trainer = TransferLearningTrainer(model, self.device)
        
        trained_model = trainer.fine_tune(
            train_loader, val_loader, 
            num_epochs=num_epochs, 
            lr=lr,
            freeze_backbone=freeze_backbone,
            unfreeze_epoch=unfreeze_epoch
        )
        
        return trained_model


